SELECT DISTINCT ?musician ?musicianLabel WHERE {
  ?musician wdt:P106 wd:Q6256 .
  ?musician wdt:P19 ?birthCity .
  ?birthCity wdt:P131 ?birthState .
  ?birthState wdt:P17 wd:Q30 .
  {
    ?birthState wd:Q1317 .
  }
  UNION
  {
    ?birthState wd:Q235 .
  }
  UNION
  {
    ?birthState wd:Q179 .
  }
  ?musician p:P1892 ?awardStatement .
  ?awardStatement ps:P1892 wd:Q66320 .
  ?awardStatement pq:P585 ?awardYear .
  FILTER (YEAR(?awardYear) = 2022)
  OPTIONAL { ?musician rdfs:label ?musicianLabel . FILTER (LANG(?musicianLabel) = "en") }
}

